import shlex

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

class SecureJobConsumer:
    def __init__(self, rabbitmq_host: str, queue_name: str, 
                 allowed_commands: List[str], 
                 hmac_secret: Optional[str] = None):
        self.rabbitmq_host = rabbitmq_host
        self.queue_name = queue_name
        self.allowed_commands = set(allowed_commands)
        self.hmac_secret = hmac_secret or os.environ.get('QUEUE_HMAC_SECRET')
        
        rabbitmq_user = os.environ.get('RABBITMQ_USER', 'guest')
        rabbitmq_pass = os.environ.get('RABBITMQ_PASS', 'guest')
        
        credentials = pika.PlainCredentials(rabbitmq_user, rabbitmq_pass)
        self.connection_params = pika.ConnectionParameters(
            host=self.rabbitmq_host,
            credentials=credentials,
            ssl_options=pika.SSLOptions() if os.environ.get('RABBITMQ_USE_SSL') else None
        )
        
    def verify_message_signature(self, message: Dict, signature: str) -> bool:
        if not self.hmac_secret:
            logger.warning("HMAC secret not configured - skipping signature verification")
            return True
            
        message_bytes = json.dumps(message, sort_keys=True).encode('utf-8')
        expected_signature = hmac.new(
            self.hmac_secret.encode('utf-8'),
            message_bytes,
            hashlib.sha256
        ).hexdigest()
        
        return hmac.compare_digest(expected_signature, signature)
    
    def validate_command(self, command: str) -> bool:
        try:
            parsed = shlex.split(command)
        except ValueError as e:
            logger.error(f"Invalid command syntax: {e}")
            return False
            
        if not parsed:
            logger.error("Empty command")
            return False
        
        base_command = parsed[0]
        
        if base_command not in self.allowed_commands:
            logger.error(f"Command '{base_command}' not in allowlist")
            return False
        
        for arg in parsed:
            if any(char in arg for char in ['&', '|', ';', '`', '$', '(', ')', '<', '>', '\n', '\r']):
                logger.error(f"Potentially dangerous characters in command argument: {arg}")
                return False
        
        return True
    
    def sanitize_environment(self) -> Dict[str, str]:
        safe_env_vars = ['PATH', 'HOME', 'USER', 'LANG', 'LC_ALL']
        sanitized_env = {}
        
        for var in safe_env_vars:
            if var in os.environ:
                sanitized_env[var] = os.environ[var]
        
        sanitized_env['PATH'] = '/usr/local/bin:/usr/bin:/bin'
        
        return sanitized_env
    
    def execute_command(self, command: str, timeout: int = 300) -> Dict:
        try:
            parsed_command = shlex.split(command)
            
            result = subprocess.run(
                parsed_command,
                capture_output=True,
                text=True,
                timeout=timeout,
                env=self.sanitize_environment(),
                shell=False,
                cwd='/tmp'
            )
            
            return {
                'success': result.returncode == 0,
                'returncode': result.returncode,
                'stdout': result.stdout[:1000],
                'stderr': result.stderr[:1000]
            }
            
        except subprocess.TimeoutExpired:
            logger.error(f"Command timed out after {timeout} seconds")
            return {
                'success': False,
                'error': 'Command execution timeout'
            }
        except Exception as e:
            logger.error(f"Command execution failed: {e}")
            return {
                'success': False,
                'error': str(e)
            }
    
    def process_message(self, ch, method, properties, body):
        try:
            message_data = json.loads(body.decode('utf-8'))
            
            if not isinstance(message_data, dict):
                logger.error("Invalid message format - not a JSON object")
                ch.basic_nack(delivery_tag=method.delivery_tag, requeue=False)
                return
            
            signature = message_data.get('signature', '')
            command = message_data.get('command', '')
            timeout = message_data.get('timeout', 300)
            
            if self.hmac_secret and not self.verify_message_signature(
                {'command': command, 'timeout': timeout}, signature
            ):
                logger.error("Message signature verification failed")
                ch.basic_nack(delivery_tag=method.delivery_tag, requeue=False)
                return
            
            if not command or not isinstance(command, str):
                logger.error("Invalid or missing command in message")
                ch.basic_nack(delivery_tag=method.delivery_tag, requeue=False)
                return
            
            if not self.validate_command(command):
                logger.error(f"Command validation failed")
                ch.basic_nack(delivery_tag=method.delivery_tag, requeue=False)
                return
            
            if not isinstance(timeout, int) or timeout < 1 or timeout > 3600:
                logger.warning(f"Invalid timeout value, using default")
                timeout = 300
            
            logger.info(f"Executing validated command")
            result = self.execute_command(command, timeout)
            
            if result['success']:
                logger.info(f"Command executed successfully")
                ch.basic_ack(delivery_tag=method.delivery_tag)
            else:
                logger.error(f"Command execution failed: {result.get('error', 'Unknown error')}")
                ch.basic_nack(delivery_tag=method.delivery_tag, requeue=False)
                
        except json.JSONDecodeError as e:
            logger.error(f"Failed to parse message JSON: {e}")
            ch.basic_nack(delivery_tag=method.delivery_tag, requeue=False)
        except Exception as e:
            logger.error(f"Unexpected error processing message: {e}")
            ch.basic_nack(delivery_tag=method.delivery_tag, requeue=False)
    
    def start_consuming(self):
        connection = pika.BlockingConnection(self.connection_params)
        channel = connection.channel()
        
        channel.queue_declare(queue=self.queue_name, durable=True)
        channel.basic_qos(prefetch_count=1)
        channel.basic_consume(
            queue=self.queue_name,
            on_message_callback=self.process_message
        )
        
        logger.info(f"Started consuming from queue: {self.queue_name}")
        try:
            channel.start_consuming()
        except KeyboardInterrupt:
            logger.info("Stopping consumer...")
            channel.stop_consuming()
        finally:
            connection.close()


